  import sailpoint.api.SailPointContext;
  import java.io.UnsupportedEncodingException;
  import java.security.MessageDigest;
  import java.security.NoSuchAlgorithmException;
  import java.util.Arrays;
  import java.util.Base64;
   
  import javax.crypto.Cipher;
  import javax.crypto.spec.SecretKeySpec;
  	
  private static SecretKeySpec secretKey;
  private static byte[] key;
  private static String secret = "h5Q.bup%k%Rv2Wp^S[yzTxFgw)X4Kr!=";

  public static void setKey(String myKey){
      MessageDigest sha = null;
      try {
          key = myKey.getBytes("UTF-8");
          sha = MessageDigest.getInstance("SHA-256");
          key = sha.digest(key);
          key = Arrays.copyOf(key, 16); 
          secretKey = new SecretKeySpec(key, "AES");
      } 
      catch (NoSuchAlgorithmException e) {
          //e.printStackTrace();
      } 
      catch (UnsupportedEncodingException e) {
          //e.printStackTrace();
      }
  }

  public static String encryptAES(String strToEncrypt){
      try{
          setKey(secret);
          Cipher cipher = Cipher.getInstance("AES/ECB/PKCS5Padding");
          cipher.init(Cipher.ENCRYPT_MODE, secretKey);
          return Base64.getEncoder().encodeToString(cipher.doFinal(strToEncrypt.getBytes("UTF-8")));
      } 
      catch (Exception e){
          System.out.println("Error while encrypting: " + e.toString());
      }
      return null;
  }

  public static String decryptAES(String strToDecrypt){
      try{
          setKey(secret);
          Cipher cipher = Cipher.getInstance("AES/ECB/PKCS5PADDING");
          cipher.init(Cipher.DECRYPT_MODE, secretKey);
          return new String(cipher.doFinal(Base64.getDecoder().decode(strToDecrypt)));
      } 
      catch (Exception e) {
          //System.out.println("Error while decrypting: " + e.toString());
      }
      return null;
  }
  
  public String getDecryptAESValue(String value){
    try{
      if(Util.isNotNullOrEmpty(value) ){
        if( Util.isNotNullOrEmpty( decryptAES(value)) ){
          value = decryptAES(value);
        }
      }
    }catch (Exception e) {
     
    }
    return value;
  }
